local Players = game:GetService("Players")
local TweenService = game:GetService("TweenService")
local RunService = game:GetService("RunService")

local player = Players.LocalPlayer
local gui = Instance.new("ScreenGui")
gui.Name = "TOCHIPYRO_UI"
gui.ResetOnSpawn = false
gui.Parent = player:WaitForChild("PlayerGui")

-- Main Frame
local frame = Instance.new("Frame")
frame.Size = UDim2.new(0, 450, 0, 280)
frame.Position = UDim2.new(0.5, -225, 0.5, -140)
frame.BackgroundColor3 = Color3.fromRGB(35, 20, 50)
frame.BackgroundTransparency = 0.5
frame.Parent = gui

local corner = Instance.new("UICorner")
corner.CornerRadius = UDim.new(0, 15)
corner.Parent = frame

local stroke = Instance.new("UIStroke")
stroke.Color = Color3.fromRGB(170, 0, 255)
stroke.Thickness = 2
stroke.Parent = frame

-- Title
local title = Instance.new("TextLabel")
title.Size = UDim2.new(1, 0, 0, 50)
title.BackgroundTransparency = 1
title.Text = "TOCHIPYRO Script"
title.Font = Enum.Font.GothamBold
title.TextScaled = true
title.Parent = frame

-- Rainbow title effect
task.spawn(function()
	local hue = 0
	while title.Parent do
		hue = (hue + 0.005) % 1
		title.TextColor3 = Color3.fromHSV(hue, 1, 1)
		task.wait()
	end
end)

-- Notification
local notify = Instance.new("TextLabel")
notify.Size = UDim2.new(0.8, 0, 0, 30)
notify.Position = UDim2.new(0.1, 0, 0.75, 0)
notify.BackgroundTransparency = 1
notify.Text = ""
notify.TextColor3 = Color3.new(1,1,1)
notify.Font = Enum.Font.Gotham
notify.TextScaled = true
notify.Parent = frame

local function ShowMessage(msg)
	notify.Text = msg
	task.wait(2)
	if notify.Text == msg then
		notify.Text = ""
	end
end

-- DUPE Button
local dupe = Instance.new("TextButton")
dupe.Size = UDim2.new(0.7, 0, 0, 50)
dupe.Position = UDim2.new(0.15, 0, 0.3, 0)
dupe.Text = "DUPE"
dupe.Font = Enum.Font.GothamBold
dupe.TextScaled = true
dupe.BackgroundColor3 = Color3.fromRGB(120, 0, 255)
dupe.Parent = frame

local dupeCorner = Instance.new("UICorner")
dupeCorner.CornerRadius = UDim.new(0, 12)
dupeCorner.Parent = dupe

dupe.MouseButton1Click:Connect(function()
	ShowMessage("CHECK INVENTORY!)")
end)

-- More Button
local more = Instance.new("TextButton")
more.Size = UDim2.new(0.7, 0, 0, 50)
more.Position = UDim2.new(0.15, 0, 0.55, 0)
more.Text = "MORE"
more.Font = Enum.Font.GothamBold
more.TextScaled = true
more.BackgroundColor3 = Color3.fromRGB(90, 0, 180)
more.Parent = frame

local moreCorner = Instance.new("UICorner")
moreCorner.CornerRadius = UDim.new(0, 12)
moreCorner.Parent = more

-- More Menu
local moreFrame = Instance.new("Frame")
moreFrame.Size = UDim2.new(0, 300, 0, 180)
moreFrame.Position = UDim2.new(0.5, -150, 0.5, -90)
moreFrame.BackgroundColor3 = Color3.fromRGB(70, 0, 120)
moreFrame.BackgroundTransparency = 0.5
moreFrame.Visible = false
moreFrame.Parent = gui

local mfCorner = Instance.new("UICorner")
mfCorner.CornerRadius = UDim.new(0, 15)
mfCorner.Parent = moreFrame

local mfStroke = Instance.new("UIStroke")
mfStroke.Color = Color3.fromRGB(200, 100, 255)
mfStroke.Thickness = 3
mfStroke.Parent = moreFrame

local bypass = Instance.new("TextButton")
bypass.Size = UDim2.new(0.8, 0, 0, 45)
bypass.Position = UDim2.new(0.1, 0, 0.2, 0)
bypass.Text = "BYPASS"
bypass.Font = Enum.Font.GothamBold
bypass.TextScaled = true
bypass.BackgroundColor3 = Color3.fromRGB(140, 0, 255)
bypass.Parent = moreFrame

local bypassCorner = Instance.new("UICorner")
bypassCorner.CornerRadius = UDim.new(0, 12)
bypassCorner.Parent = bypass

local closeBtn = Instance.new("TextButton")
closeBtn.Size = UDim2.new(0.8, 0, 0, 45)
closeBtn.Position = UDim2.new(0.1, 0, 0.6, 0)
closeBtn.Text = "CLOSE UI"
closeBtn.Font = Enum.Font.GothamBold
closeBtn.TextScaled = true
closeBtn.BackgroundColor3 = Color3.fromRGB(255, 60, 60)
closeBtn.Parent = moreFrame

local closeCorner = Instance.new("UICorner")
closeCorner.CornerRadius = UDim.new(0, 12)
closeCorner.Parent = closeBtn

more.MouseButton1Click:Connect(function()
	moreFrame.Visible = not moreFrame.Visible
end)

bypass.MouseButton1Click:Connect(function()
	ShowMessage("Bypass Enabled (Visual Only)")
	mfStroke.Color = Color3.fromRGB(
		math.random(100,255),
		math.random(100,255),
		math.random(100,255)
	)
end)

closeBtn.MouseButton1Click:Connect(function()
	gui.Enabled = false
end)

